import Fastify from 'fastify'
import cors from '@fastify/cors'
import multipart from '@fastify/multipart'
import { DB_PATH, HOST, PORT, UPLOADS_DIR } from './config.ts'
import { routes } from './routes/learning.ts'
import { db, SCHEMA_SQL } from './db.ts'
import { mkdirSync } from 'node:fs'
import { dirname } from 'node:path'
import { uploadAndConvert } from './services/documents.ts'

const app = Fastify({ logger: true })

await app.register(cors, {
  origin: ['http://localhost:5173', 'http://127.0.0.1:5173'],
  credentials: true
})

await app.register(multipart, {
  limits: { fileSize: 1024 * 1024 * 10 } // Max 10 MB.
})

app.get('/api/health', async () => ({ ok: true }))

app.post('/api/documents/upload', async (req, reply) => {
  const part = await req.file()
  if (!part) {
    return reply.code(400).send({ error: 'No file provided' })
  }
  const allowed = ['.pdf']
  const lower = part.filename.toLowerCase()
  if (!allowed.some((ext) => lower.endsWith(ext))) {
    return reply.code(400).send({ error: 'Only PDF files are supported' })
  }
  const buffer = await part.toBuffer()
  const doc = await uploadAndConvert(part.filename, buffer)
  return reply.code(201).send(doc)
})

await app.register(routes)

function init(): void {
  mkdirSync(dirname(DB_PATH), { recursive: true })
  mkdirSync(UPLOADS_DIR, { recursive: true })
  db.exec(SCHEMA_SQL)
}

init()

app.listen({ port: PORT, host: HOST }, (err, address) => {
  if (err) {
    app.log.error(err)
    process.exit(1)
  }
  app.log.info(`Server listening on ${address}`)
})

